import numpy as np
from collections import defaultdict

class CharTokenizer:
    def __init__(self):
        self.char2id = {}
        self.id2char = {}
        self.vocab_size = 0
        self.unk_id = None

    def fit(self, text):
        unique_chars = sorted(set(text))
        self.char2id = {c: i for i, c in enumerate(unique_chars)}
        self.id2char = {i: c for c, i in self.char2id.items()}
        self.vocab_size = len(unique_chars)
        return self

    def encode(self, text):
        result = []
        for c in text:
            if c in self.char2id:
                result.append(self.char2id[c])
            # Skip unknown characters
        return result

    def decode(self, ids):
        return ''.join(self.id2char.get(i, '') for i in ids)


class NGramLM:
    def __init__(self, n=3):
        self.n = n
        self.context_len = n - 1
        # counts[(context_tuple)][next_token] = count
        self.counts = defaultdict(lambda: defaultdict(int))
        self.context_totals = defaultdict(int)
        self.vocab_size = 0
        self.vocab = set()

    def fit(self, tokens):
        self.vocab = set(tokens)
        self.vocab_size = len(self.vocab)
        for i in range(len(tokens) - self.n + 1):
            context = tuple(tokens[i:i + self.context_len])
            next_tok = tokens[i + self.context_len]
            self.counts[context][next_tok] += 1
            self.context_totals[context] += 1
        return self

    def prob(self, context, next_token):
        ctx = tuple(context[-self.context_len:]) if self.context_len > 0 else ()
        count_ctx_w = self.counts[ctx].get(next_token, 0)
        count_ctx = self.context_totals.get(ctx, 0)
        # Laplace (add-1) smoothing
        return (count_ctx_w + 1) / (count_ctx + self.vocab_size)

    def next_token_probs(self, context):
        ctx = tuple(context[-self.context_len:]) if self.context_len > 0 else ()
        probs = np.zeros(self.vocab_size)
        count_ctx = self.context_totals.get(ctx, 0)
        for tok_id in range(self.vocab_size):
            count_ctx_w = self.counts[ctx].get(tok_id, 0)
            probs[tok_id] = (count_ctx_w + 1) / (count_ctx + self.vocab_size)
        # Normalize (already normalized by Laplace, but ensure sum=1)
        total = probs.sum()
        return probs / total


class BeamSearch:
    def __init__(self, lm, vocab_size):
        self.lm = lm
        self.vocab_size = vocab_size

    def search(self, start_tokens, max_len, beam_width=3):
        # Each hypothesis: (log_prob, token_sequence)
        beams = [(0.0, list(start_tokens))]
        for _ in range(max_len):
            candidates = []
            for log_prob, seq in beams:
                context = seq
                probs = self.lm.next_token_probs(context)
                # Get top beam_width candidates for this hypothesis
                top_indices = np.argsort(probs)[::-1][:beam_width]
                for tok in top_indices:
                    new_log_prob = log_prob + np.log(probs[tok] + 1e-10)
                    candidates.append((new_log_prob, seq + [int(tok)]))
            # Keep top beam_width candidates across all expansions
            candidates.sort(key=lambda x: x[0], reverse=True)
            beams = candidates[:beam_width]
        # Return the best sequence
        best_log_prob, best_seq = beams[0]
        return best_seq


class LanguageModel:
    def __init__(self, n=3):
        self.n = n
        self.tokenizer = CharTokenizer()
        self.lm = NGramLM(n=n)

    def fit(self, corpus):
        self.tokenizer.fit(corpus)
        tokens = self.tokenizer.encode(corpus)
        self.lm.vocab_size = self.tokenizer.vocab_size
        self.lm.vocab = set(range(self.tokenizer.vocab_size))
        self.lm.fit(tokens)
        return self

    def generate(self, prompt, max_len=50, beam_width=3):
        start_tokens = self.tokenizer.encode(prompt)
        if not start_tokens:
            # Use first character of training data as start
            start_tokens = [0]
        extended = self.lm.search_wrapper(start_tokens, max_len, beam_width) if hasattr(self.lm, 'search_wrapper') else None
        # Use BeamSearch directly
        bs = BeamSearch(self.lm, self.tokenizer.vocab_size)
        result_tokens = bs.search(start_tokens, max_len=max_len, beam_width=beam_width)
        return self.tokenizer.decode(result_tokens)

    def greedy_generate(self, prompt, max_len=50):
        return self.generate(prompt, max_len=max_len, beam_width=1)
